-- Generated by AutomateDV (formerly known as dbtvault)

    

WITH source_data AS (
    SELECT a.ORDER_HK, a.ORDER_HASHDIFF, a.ORDER_DATE, a.TOTAL_AMOUNT, a.STATUS, a.EFFECTIVE_FROM, a.LOAD_DATE, a.RECORD_SOURCE
    FROM POC_DBT_PROJECT.UTILS_staging.stg_orders AS a
    WHERE a.ORDER_HK IS NOT NULL
),

latest_records AS (
    SELECT current_records.ORDER_HK, current_records.ORDER_HASHDIFF, current_records.LOAD_DATE
    FROM POC_DBT_PROJECT.UTILS_raw_vault.sat_order AS current_records
    JOIN (
        SELECT DISTINCT source_data.ORDER_HK
        FROM source_data
    ) AS source_records
        ON source_records.ORDER_HK = current_records.ORDER_HK
    QUALIFY ROW_NUMBER() OVER (
        PARTITION BY current_records.ORDER_HK
        ORDER BY current_records.LOAD_DATE DESC
    ) = 1
),

unique_source_records AS (
    SELECT
        sd.ORDER_HK, sd.ORDER_HASHDIFF, sd.ORDER_DATE, sd.TOTAL_AMOUNT, sd.STATUS, sd.EFFECTIVE_FROM, sd.LOAD_DATE, sd.RECORD_SOURCE
    FROM source_data AS sd
    LEFT OUTER JOIN latest_records AS lr
        ON sd.ORDER_HK = lr.ORDER_HK

    QUALIFY sd.ORDER_HASHDIFF !=
        LAG(sd.ORDER_HASHDIFF, 1,
            COALESCE(
                lr.ORDER_HASHDIFF,
                CAST('FFFFFFFF' AS BINARY(16))
            )
        ) OVER (
            PARTITION BY sd.ORDER_HK
            ORDER BY sd.LOAD_DATE ASC,
                     sd.EFFECTIVE_FROM ASC
        )
),

records_to_insert AS (
    SELECT usr.ORDER_HK, usr.ORDER_HASHDIFF, usr.ORDER_DATE, usr.TOTAL_AMOUNT, usr.STATUS, usr.EFFECTIVE_FROM, usr.LOAD_DATE, usr.RECORD_SOURCE
    FROM unique_source_records AS usr
)

SELECT * FROM records_to_insert